import{_ as s,c as a,o as n,a as e}from"./app.34ee827a.js";const o="/vue-docker/assets/production.11466d7b.png",A=JSON.parse('{"title":"Modo Producci\xF3n","description":"","frontmatter":{},"headers":[{"level":2,"title":"Dockerfile","slug":"dockerfile","link":"#dockerfile","children":[]}],"relativePath":"guide/production-mode.md"}'),l={name:"guide/production-mode.md"},p=e(`<h1 id="modo-produccion" tabindex="-1">Modo Producci\xF3n <a class="header-anchor" href="#modo-produccion" aria-hidden="true">#</a></h1><blockquote><p><strong>\xBFCu\xE1l es la diferecia en esta configuraci\xF3n versus la versi\xF3n de desarrollo?</strong></p></blockquote><p>\u{1F4C3}<code>docker-compose.yml</code></p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">version: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">3.9</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">services:</span></span>
<span class="line"><span style="color:#A6ACCD;">  web:</span></span>
<span class="line"><span style="color:#A6ACCD;">    build:</span></span>
<span class="line"><span style="color:#A6ACCD;">      context: </span><span style="color:#82AAFF;">.</span></span>
<span class="line"><span style="color:#A6ACCD;">      dockerfile: Dockerfile</span></span>
<span class="line"><span style="color:#A6ACCD;">    ports:</span></span>
<span class="line"><span style="color:#A6ACCD;">      - </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">80:80</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">    environment:</span></span>
<span class="line"><span style="color:#A6ACCD;">      NODE_ENV: production</span></span>
<span class="line"><span style="color:#A6ACCD;">    container_name: vue_dev_env</span></span>
<span class="line"></span></code></pre></div><ul><li>Compilaci\xF3n especificada desde <code>Dockerfile</code> en lugar de usar una <code>image</code>.</li><li>La variable de entorno <code>NODE_ENV</code> cambi\xF3: <code>development</code> -&gt; <code>production</code>.</li><li>No hay una secci\xF3n de comandos porque <code>nginx</code> servir\xE1 la est\xE1tica.</li></ul><p>La configuraci\xF3n de <code>nginx</code> es lo m\xE1s simple posible y no sobrecarga el proceso de entrega de archivos y recurre a <code>/index.html</code> en caso de que intenten obtener alg\xFAn archivo que no est\xE9 all\xED. Lo m\xE1s interesante radica en el <code>Dockerfile</code>: construcci\xF3n de varias etapas (<em>multi-stage</em>), que se utiliza para reducir el artefacto resultante.</p><h2 id="dockerfile" tabindex="-1">Dockerfile <a class="header-anchor" href="#dockerfile" aria-hidden="true">#</a></h2><p>\u{1F4C3}<code>Dockerfile</code></p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">FROM node:18.8.0 AS build</span></span>
<span class="line"><span style="color:#A6ACCD;">WORKDIR /app</span></span>
<span class="line"><span style="color:#A6ACCD;">COPY package.json package.json</span></span>
<span class="line"><span style="color:#A6ACCD;">RUN npm install</span></span>
<span class="line"><span style="color:#A6ACCD;">COPY </span><span style="color:#82AAFF;">.</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">.</span></span>
<span class="line"><span style="color:#A6ACCD;">RUN npm run build</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">FROM nginx:1.23.1</span></span>
<span class="line"><span style="color:#A6ACCD;">COPY --from=build /app/dist /opt/site</span></span>
<span class="line"><span style="color:#A6ACCD;">COPY nginx.conf /etc/nginx/nginx.conf</span></span>
<span class="line"></span></code></pre></div><p><strong>La primera etapa es <code>build</code>.</strong></p><ol><li>Para ello, especificamos la misma imagen de origen que se utiliz\xF3 para desarrollar. <code>FROM node:18.8.0 AS build</code>. \xA1Importante! Le damos a la etapa el nombre <code>build</code> para que en las siguientes etapas se llame por su nombre, y no por su \xEDndice, que puede cambiar si incluimos etapas adicionales.</li><li>Especifique el <code>WORKDIR /app</code>.</li><li><strong>Pregunta</strong>: \xBFpor qu\xE9 primero copiamos solo <code>package.json</code> y lo instalamos? La <strong>respuesta</strong> (no se hace esperar mucho): la primera vez que ejecute la diferencia no se notar\xE1, pero la diferencia ser\xE1 obvia en el pr\xF3ximo intento de compilaci\xF3n. Si no hubo cambios en <code>package.json</code>, las capas sobre las que se construye <em><strong>docker</strong></em> no cambiar\xE1n, y estos pasos simplemente se tomar\xE1n del <em><strong>cach\xE9</strong></em>. Esto acelerar\xE1 enormemente el proceso y reducir\xE1 varias veces la carga de la red. Solo necesitamos esto.</li><li>Copiar los archivos restantes y ejecutar la construcci\xF3n.</li></ol><p><strong>La segunda etapa es la formaci\xF3n de un artefacto.</strong></p><p>En esencia, un artefacto en nuestro caso es un contenedor <code>nginx</code> con est\xE1tica.</p><ol start="5"><li>Especificamos la imagen <code>FROM nginx:1.23.1</code> que tomaremos como base.</li><li>Copiamos los archivos desde la primera etapa a la carpeta a la que distribuiremos las est\xE1ticas.</li><li>Copiamos el archivo de configuraci\xF3n de <code>nginx</code> en el artefacto.</li></ol><p>Puede ejecutar el artefacto de esta manera:</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">docker-compose up -d --build</span></span>
<span class="line"></span></code></pre></div><p>Docker comenzar\xE1 con el proceso de instaci\xF3n y finalizar\xE1 con un mensaje como el siguiente:</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">Successfully built 5103e27c5863</span></span>
<span class="line"><span style="color:#A6ACCD;">Successfully tagged docker-vue-example_web:latest</span></span>
<span class="line"><span style="color:#A6ACCD;">Recreating vue_dev_env ... </span><span style="color:#89DDFF;">done</span></span>
<span class="line"></span></code></pre></div><p>Inspeccionemos la direcci\xF3n <strong>IP</strong> otorgada por <em>Docker</em> a nuestro contenedor <code>vue_dev_env</code> con el siguiente comando.</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">docker inspect vue_dev_env</span></span>
<span class="line"></span></code></pre></div><p>Y deber\xE1 aparecer al final un mensaje como este:</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">NetworkID</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">04608c48ec451acd128c224efa450d0334a7d0cccc3b14c2ec760b1d2c8bc4dc</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">EndpointID</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">32e900e38758c907bc25212e984944494957de446f5644c7799bc74c51696b9d</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Gateway</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">192.168.32.1</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">IPAddress</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">192.168.32.2</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">IPPrefixLen</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: 20,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">IPv6Gateway</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">&quot;&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">GlobalIPv6Address</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">&quot;&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">GlobalIPv6PrefixLen</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: 0,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">MacAddress</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">02:42:c0:a8:20:02</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">          </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">DriverOpts</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">: null</span></span>
<span class="line"><span style="color:#A6ACCD;">        }</span></span>
<span class="line"><span style="color:#A6ACCD;">      }</span></span>
<span class="line"><span style="color:#A6ACCD;">    }</span></span>
<span class="line"><span style="color:#A6ACCD;">  }</span></span>
<span class="line"><span style="color:#A6ACCD;">]</span></span>
<span class="line"></span></code></pre></div><p>Ok, ahora copie y pegue tal cual la direcci\xF3n <strong>IP</strong> en la <strong>URL</strong> del navegador.</p><p><img src="`+o+'" alt="production"></p>',24),c=[p];function t(r,i,d,D,u,C){return n(),a("div",null,c)}const m=s(l,[["render",t]]);export{A as __pageData,m as default};
